    `Severity: ${issue.severity} · Status: ${issue.status}`,
    `Affected NAS: ${issue.affected_nas.join(", ") || "unknown"}`,
    issue.current_hypothesis ? `Current hypothesis (${issue.hypothesis_confidence ?? "?"}): ${issue.current_hypothesis}` : "",

