                sending={loading}
                waitingOnUser={current.resolution.status === "waiting_on_user"}
              />
            </div>
          </div>
          <DiagnosisRail
            state={current}
            forensicSlot={<ForensicIncidentPanel facts={current.facts} />}
          />
        </main>
      )}
    </div>
  );
